extra.modelCss:
/* Display na prática */

.box {
  display: block;
  width: 280px;
  padding: 16px;
  border: 1px solid #ddd;
}

.link-as-btn {
  display: inline-block;
  padding: 10px 14px;
  border-radius: 10px;
  background: #111;
  color: #fff;
}

.hidden {
  display: none;
}

.invisible {
  visibility: hidden;
}
